const READ_TIMES = ['4 min read','5 min read','6 min read','7 min read','8 min read','10 min read'];

function makeExcerpt(title, cat) {
  const m = {
    'uae-destinations':'Complete guide covering everything you need — timings, tickets, insider tips from guides who work here every day.',
    'worldwide-tours':'Everything you need to plan the perfect trip from Dubai — best time to go, what to see, and how DubaiRovers makes it effortless.',
    'gulf-comparisons':'An honest practical comparison based on thousands of guest reviews and firsthand experience to help you choose.',
    'adventure':'Complete guide covering safety, operators, costs, and the insider knowledge that makes the difference between good and extraordinary.',
    'family-travel':'What actually works when travelling with children — from a team that runs family tours every week.',
    'food-culture':'Beyond TripAdvisor: where locals eat, what they order, and what every guidebook misses.',
    'luxury-travel':'Honest assessment of what is genuinely worth the premium — and what is mostly brand value.',
    'budget-travel':'The practical guide to doing it properly on a budget — no compromise on experience, just smarter choices.',
    'safety-tips':'Everything practical before you go — not generic advice, but specific honest guidance from experienced guides.',
    'weather-seasonal':'The honest seasonal guide with what it actually feels like to visit at different times of year.',
    'occasions-events':'Our honest guide to creating genuinely memorable special occasions — venues, experiences, and insider details.',
    'tour-guides':'Written by the team that runs this tour daily — not from a brochure, from actual experience.',
  };
  return m[cat] || `Expert guidance from Dubai's most trusted tour operator. Free hotel pickup on most tours.`;
}

export const ALL_BLOGS = MASTER.map((b, i) => {
  const isPast = b.d <= 0;
  const status = isPast ? 'published' : (b.d <= 14 ? 'scheduled' : 'draft');
  const publishAt = isPast ? pastDate(Math.abs(b.d)) : scheduleDate(b.d);
  return {
    id: `blog-${i+1}`,
    slug: makeSlug(b.c),
    title: b.c,
    excerpt: makeExcerpt(b.cat, b.cat),
    category: b.cat || b.c,
    author: AUTHORS[i % AUTHORS.length],
    publishAt,
    publishedAt: isPast ? publishAt.split('T')[0] : null,
    status,
    image: b.img || 'https://images.unsplash.com/photo-1518684079-3c830dcef090?w=800&q=80',
    readTime: READ_TIMES[i % READ_TIMES.length],
    views: isPast ? Math.floor(Math.random()*8000)+300 : 0,
    featured: i < 8,
    tags: [b.cat, 'Dubai', 'Travel'],
    seoTitle: `${b.c} | DubaiRovers`,
    seoDesc: `${b.c.slice(0,100)} — Expert guide from Dubai's number one tour operator.`,
    content: generateBlogContent(b.c, b.cat),
  };
});

export const AUTO_LINK_MAP = [
  {keywords:['desert safari','dune bashing','bedouin camp','camel ride'],          tourSlug:'evening-desert-safari-dubai',         label:'🏜️ Desert Safari'},
  {keywords:['abu dhabi','sheikh zayed mosque','ferrari world','emirates palace'], tourSlug:'abu-dhabi-city-tour-from-dubai',        label:'🕌 Abu Dhabi Tour'},
  {keywords:['dubai city tour','gold souk','dubai creek','al fahidi'],             tourSlug:'dubai-city-tour-full-day',             label:'🏙️ Dubai City Tour'},
  {keywords:['dhow cruise','marina cruise','dinner cruise'],                        tourSlug:'dubai-marina-dhow-cruise-dinner',      label:'🚢 Dhow Cruise'},
  {keywords:['helicopter','aerial tour'],                                           tourSlug:'helicopter-tour-dubai-palm',           label:'🚁 Helicopter Tour'},
  {keywords:['overnight safari','sleep in desert'],                                 tourSlug:'overnight-desert-safari-dubai',        label:'🌙 Overnight Desert'},
  {keywords:['burj khalifa','at the top'],                                          tourSlug:'burj-khalifa-at-the-top',              label:'🏙️ Burj Khalifa'},
  {keywords:['paris','eiffel tower'],                                               tourSlug:'paris-france-tour-package-from-dubai', label:'🗼 Paris Package'},
];

export function applyAutoLinks(content, tours=[]) {
  if (!content) return content;
  let r = content;
  AUTO_LINK_MAP.forEach(({keywords,tourSlug,label}) => {
    const tour = tours.find(t=>t.slug===tourSlug);
    if (!tour) return;
    keywords.forEach(kw => {
      r = r.replace(new RegExp(`(?<![">])\\b(${kw})\\b(?![^<]*<\\/a>)`,'gi'),
        `<a href="/tours/${tour.category}/${tour.slug}" class="text-brand-gold font-semibold hover:underline" title="${label}">$1</a>`);
    });
  });
  return r;
}

export default ALL_BLOGS;
